Here's a simple jumping game using JavaScript and HTML5 Canvas. Create an `index.html` file and add the following code:

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Jumping Game</title>
    <style>
        canvas {
            display: block;
            margin: auto;
            background-color: #f0f0f0;
        }
    </style>
</head>
<body>
    <canvas id="gameCanvas" width="640" height="360"></canvas>
    <script>
        const canvas = document.getElementById("gameCanvas");
        const ctx = canvas.getContext("2d");

        const gravity = 0.5;
        const groundHeight = 40;

        let isJumping = false;
        let jumpHeight = 0;
        let velocity = 0;

        const character = {
            x: 100,
            y: canvas.height - groundHeight - 50,
            width: 50,
            height: 50,
        };

        function startJump() {
            if (!isJumping) {
                isJumping = true;
                velocity = -15;
            }
        }

        function update() {
            if (isJumping) {
                character.y += velocity;
                velocity += gravity;
                if (character.y >= canvas.height - groundHeight - character.height) {
                    character.y = canvas.height - groundHeight - character.height;
                    isJumping = false;
                }
            }
            draw();
        }

        function draw() {
            // Clear canvas
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            // Draw character
            ctx.fillStyle = "#000";
            ctx.fillRect(character.x, character.y, character.width, character.height);

            // Draw ground
            ctx.fillStyle = "#444";
            ctx.fillRect(0, canvas.height - groundHeight, canvas.width, groundHeight);
        }

        // Mouse event to trigger jump
        canvas.addEventListener("mousedown", startJump);

        // Keyboard event `space` to trigger jump
        document.addEventListener("keydown", (event) => {
            if (event.code === "Space") {
                event.preventDefault(); // prevent scrolling the web page
                startJump();
            }
        });

        setInterval(update, 1000/60); // 60 FPS
    </script>
</body>
</html>
```

In this game, we have a simple character represented by a square that can jump when you click the canvas or press the space key. The character is affected by gravity, and there's a ground to indicate when the jump is over.

To run the game, simply open the `index.html` file in your web browser.

